def merge_configs(base, override, merge_strategy="deep"):
    """Merge override into base config.

    If merge_strategy is 'shallow', performs a shallow merge.
    If merge_strategy is 'deep', recursively merges nested dicts.
    """
    if merge_strategy == "shallow":
        return {**base, **override}

    # deep merge – recursively merge nested dictionaries without mutating base
    merged = {}
    # copy all keys from base first, but we will update with override values
    for key in base:
        if key in override:
            # both exist: if both are dicts, deep merge; else override wins
            if isinstance(base[key], dict) and isinstance(override[key], dict):
                merged[key] = merge_configs(base[key], override[key], merge_strategy="deep")
            else:
                merged[key] = override[key]
        else:
            merged[key] = base[key]
    # add keys that are only in override
    for key in override:
        if key not in base:
            merged[key] = override[key]
    return merged
