import ast
import operator

# Mapping of AST operator nodes to Python operator functions
_BIN_OPS = {
    ast.Add: operator.add,
    ast.Sub: operator.sub,
    ast.Mult: operator.mul,
    ast.Div: operator.truediv,
}

_UNARY_OPS = {
    ast.UAdd: operator.pos,
    ast.USub: operator.neg,
}

_ALLOWED_OPS = set(_BIN_OPS.keys()) | set(_UNARY_OPS.keys())


def _safe_eval_node(node):
    """Recursively evaluate an AST node with allowed operations only."""
    if isinstance(node, ast.Constant) and isinstance(node.value, (int, float)):
        return node.value
    elif isinstance(node, ast.Num):  # backward compatibility for Python<3.8
        return node.n
    elif isinstance(node, ast.UnaryOp):
        if type(node.op) not in _UNARY_OPS:
            raise ValueError(f"Unsupported unary operator: {type(node.op).__name__}")
        operand = _safe_eval_node(node.operand)
        return _UNARY_OPS[type(node.op)](operand)
    elif isinstance(node, ast.BinOp):
        if type(node.op) not in _BIN_OPS:
            raise ValueError(f"Unsupported binary operator: {type(node.op).__name__}")
        left = _safe_eval_node(node.left)
        right = _safe_eval_node(node.right)
        op_func = _BIN_OPS[type(node.op)]
        if op_func is operator.truediv and right == 0:
            raise ZeroDivisionError("Division by zero")
        return op_func(left, right)
    elif isinstance(node, ast.Expression):
        return _safe_eval_node(node.body)
    else:
        raise ValueError(f"Unsupported node type: {type(node).__name__}")


def evaluate_expression(expr):
    """Evaluate a mathematical expression safely using AST.

    Supports: numbers, +, -, *, /, parentheses, unary + and -.
    Raises ValueError or ZeroDivisionError on invalid input.
    """
    try:
        tree = ast.parse(expr.strip(), mode='eval')
    except SyntaxError as e:
        raise ValueError(f"Invalid syntax: {e}") from e

    return _safe_eval_node(tree)
