def parse_entry(line):
    """
    Parse a string of the form 'key: value' and return a (key, value) tuple.
    Values that look like numbers are converted to int or float.
    Returns None for malformed input.
    """
    if not isinstance(line, str):
        return None

    # Split on the first colon only
    parts = line.split(':', 1)
    if len(parts) != 2:
        return None

    key = parts[0].strip()
    value = parts[1].strip()

    # Key cannot be empty
    if not key:
        return None

    # Attempt numeric conversion
    converted_value = value
    if value:
        # Try int first (no decimal point)
        if '.' not in value and 'e' not in value.lower():
            try:
                converted_value = int(value)
            except ValueError:
                # Not an int, leave as string
                pass
        else:
            # Try float (includes scientific notation)
            try:
                converted_value = float(value)
            except ValueError:
                # Not a float, leave as string
                pass

    return (key, converted_value)
